/**
 * @summary List trades recorded on the smart contract
 */
export const getListOnChainTradesUrl = (params?: ListOnChainTradesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/chain/on-chain-trades?${stringifiedParams}`
    : `/api/chain/on-chain-trades`;
};

export const listOnChainTrades = async (
  params?: ListOnChainTradesParams,
  options?: RequestInit,
): Promise<OnChainTrade[]> => {
  return customFetch<OnChainTrade[]>(getListOnChainTradesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListOnChainTradesQueryKey = (
  params?: ListOnChainTradesParams,
) => {
  return [`/api/chain/on-chain-trades`, ...(params ? [params] : [])] as const;
};

